#include "interface.h"

namespace {

inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}  // namespace

uint64_t newline_split_checksum(const std::string& text, int iters) {
  uint64_t final_hash = 0;
  const char* data = text.data();
  const size_t size = text.size();

  for (int iter = 0; iter < iters; ++iter) {
    uint64_t hash = 1469598103934665603ULL;
    size_t start = 0;

    while (start < size) {
      size_t end = start;
      while (end < size && data[end] != '\n') {
        ++end;
      }

      size_t len = end - start;
      hash = mix(hash, (uint64_t)len);
      hash = mix(hash, len == 0 ? 0u : static_cast<unsigned char>(data[start]));

      start = end + 1;
    }

    // Handle trailing newline case: if the text ends with '\n', 
    // the loop above finishes, but the reference implementation 
    // would have processed one last empty string if start == size
    // However, the baseline logic `while (start < text.size())` 
    // means if the last char is '\n', start becomes text.size() 
    // and the loop terminates without adding a final empty line.
    // If the text is empty, the loop doesn't run.

    // Special case: if the string ends with '\n', the baseline 
    // `while (start < text.size())` does NOT produce a trailing empty line.
    // If the string is empty, it produces no lines.

    final_hash = hash;
  }
  return final_hash;
}
